import React, { useState } from "react";

const FIELDS = [
  "SUMMARY",
  "EDUCATION",
  "COMPETENCIES",
  "EXPERIENCE",
  "PROJECTS",
  "CERTS"
];

export default function App() {
  const [text, setText] = useState("");
  const [loading, setLoading] = useState(false);
  const [backendUrl, setBackendUrl] = useState("http://localhost:4000");

  async function handleGenerateAll(e) {
    e.preventDefault();
    setLoading(true);
    try {
      // Step 1. Ask backend AI to generate all fields from job desc
      const aiResponse = await fetch(`${backendUrl}/api/generate`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          description: text
          // (no fields: backend returns all)
        })
      });
      const aiFields = await aiResponse.json();
      if (!aiResponse.ok || !aiFields["summary"]) {
        alert('Error: ' + (aiFields.error || 'No content generated!'));
        setLoading(false);
        return;
      }

      // Step 2. Inject all fields into the template and get PDF
      // Prepare replacements object: capitalize keys for the backend template
      const replacements = {};
      for (const f of FIELDS) {
        if (aiFields[f.toLowerCase()]) {
          replacements[f] = aiFields[f.toLowerCase()];
        }
      }

      const pdfResponse = await fetch(`${backendUrl}/api/inject`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ replacements }),
      });

      if (!pdfResponse.ok) {
        const err = await pdfResponse.json();
        alert("Error: " + (err.error || JSON.stringify(err)));
        setLoading(false);
        return;
      }

      const blob = await pdfResponse.blob();
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = "custom_resume.pdf";
      a.click();
      URL.revokeObjectURL(url);

    } catch (err) {
      alert("Network error: " + err.message);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div style={{ padding: 20, fontFamily: "Arial, sans-serif", maxWidth: 800, margin: "auto" }}>
      <h2>Auto Resume Builder — One-Click AI Resume from Job Ad</h2>
      <p>
        Paste the <b>job description/requirements</b> below.<br />
        Click <b>Generate Resume PDF</b>.<br />
        The AI will auto-fill ALL major sections of your resume and you’ll get a ready-to-use PDF!
      </p>
      <div style={{ marginBottom: 8 }}>
        <label>Backend URL: </label>
        <input value={backendUrl} onChange={e => setBackendUrl(e.target.value)} style={{ width: 300 }} />
        <small style={{ marginLeft: 8, color: "#666" }}>e.g. http://localhost:4000</small>
      </div>
      <form onSubmit={handleGenerateAll}>
        <textarea
          value={text}
          onChange={e => setText(e.target.value)}
          rows={14}
          style={{ width: "100%", padding: 8 }}
          placeholder="Paste the entire job description/requirements here. AI will generate each major section of your resume to fit the job."
          required
        />
        <div style={{ marginTop: 10 }}>
          <button type="submit" disabled={loading || !text.trim()}>{loading ? "Generating..." : "Generate Resume PDF"}</button>
        </div>
      </form>
    </div>
  );
}
